import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.smith.langchain.com/reference/api";
const PLACEHOLDER_VALUE = "lsv2_pt_c0ffeesafe10ca1c0ffeesafe10ca1c0_ffee5afe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from LangSmith API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:langsmith",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const langsmithFirewall = {",
    '  name: "langsmith",',
    '  description: "LangSmith",',
    "  placeholders: {",
    `    LANGSMITH_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.smith.langchain.com",',
    "      auth: {",
    "        headers: {",
    '          "X-Api-Key": "${{ secrets.LANGSMITH_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating LangSmith firewall config...");
  const ts = generateTypeScript();
  writeOutput("langsmith", ts, import.meta.dirname);
}
